import React, { useState, useEffect } from 'react';
import { Users, Building2, TrendingUp, Activity, Calendar, DollarSign, UserCheck, Briefcase } from 'lucide-react';
import { format } from 'date-fns';

const StatCard = ({ title, value, icon: Icon, color, change }) => (
  <div className="card">
    <div className="flex items-center justify-between">
      <div>
        <p className="text-sm font-medium text-gray-600">{title}</p>
        <p className="text-2xl font-bold text-gray-900 mt-2">{value}</p>
        {change && (
          <p className={`text-sm mt-2 ${change >= 0 ? 'text-green-600' : 'text-red-600'}`}>
            {change >= 0 ? '+' : ''}{change}% from last month
          </p>
        )}
      </div>
      <div className={`p-3 rounded-lg ${color}`}>
        <Icon className="h-6 w-6 text-white" />
      </div>
    </div>
  </div>
);

const RecentActivity = ({ title, items, type }) => {
  const getTypeColor = (active) => active ? 'status-active' : 'status-inactive';

  return (
    <div className="card">
      <h3 className="text-lg font-semibold text-gray-900 mb-4">{title}</h3>
      <div className="space-y-3">
        {items?.slice(0, 5).map((item) => (
          <div key={item.id} className="flex items-center justify-between py-2">
            <div className="flex-1">
              <p className="text-sm font-medium text-gray-900">
                {type === 'student' ? item.fullName : item.companyName}
              </p>
              <p className="text-xs text-gray-500">
                {type === 'student' ? item.email : item.industry}
              </p>
            </div>
            <div className="text-right">
              <span className={`status-badge ${getTypeColor(item.active)}`}>
                {item.active ? 'Active' : 'Inactive'}
              </span>
              <p className="text-xs text-gray-500 mt-1">
                {format(new Date(item.registrationDate), 'MMM dd, yyyy')}
              </p>
            </div>
          </div>
        ))}
        {(!items || items.length === 0) && (
          <p className="text-gray-500 text-center py-4">No recent {type}s</p>
        )}
      </div>
    </div>
  );
};

